import { useState } from 'react'
import { useAuth } from '../lib/AuthContext'

var LOGO = ""

export default function LoginPage() {
  var auth = useAuth()
  var [email, setEmail] = useState('')
  var [pw, setPw] = useState('')
  var [err, setErr] = useState('')
  var [loading, setLoading] = useState(false)

  async function handle(e) {
    e.preventDefault()
    setLoading(true)
    setErr('')
    var result = await auth.signIn(email, pw)
    if (result.error) setErr('E-mail ou senha incorretos.')
    setLoading(false)
  }

  return (
    <div style={{ background: 'linear-gradient(135deg,#0a0900 0%,#120f05 100%)', minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600&display=swap');
        *{box-sizing:border-box;margin:0;padding:0}
        .lc{background:#141209;border:1px solid #2a2415;border-radius:16px;padding:48px 40px;width:420px;max-width:95vw;box-shadow:0 25px 60px rgba(0,0,0,.6),0 0 0 1px #c9a96e15}
        .li{background:#1c1810;border:1.5px solid #2a2415;color:#f0ead8;padding:13px 16px;font-size:15px;width:100%;outline:none;font-family:Inter,sans-serif;transition:all .2s;border-radius:8px}
        .li:focus{border-color:#c9a96e;background:#221e12;box-shadow:0 0 0 3px #c9a96e18}
        .li::placeholder{color:#4a4030}
        .lb{background:linear-gradient(135deg,#c9a96e,#a07840);color:#0a0900;border:none;padding:14px;width:100%;font-family:Inter,sans-serif;font-size:15px;font-weight:600;letter-spacing:.08em;cursor:pointer;border-radius:8px;transition:all .2s}
        .lb:hover{transform:translateY(-1px);box-shadow:0 6px 20px #c9a96e40}
        .lb:disabled{opacity:.5;cursor:not-allowed;transform:none}
        .ll{display:block;font-size:11px;font-weight:500;letter-spacing:.1em;color:#7a6a4a;text-transform:uppercase;margin-bottom:8px;font-family:Inter,sans-serif}
        @keyframes fu{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:translateY(0)}}
        .fu{animation:fu .5s ease forwards}
      `}</style>
      <div className="lc fu" style={{ fontFamily: 'Inter,sans-serif' }}>
        <div style={{ textAlign:'center', marginBottom:40 }}>
          <img src={"data:image/jpeg;base64,"+LOGO} alt="Outliers" style={{ width:100,height:100,objectFit:'contain',borderRadius:12,marginBottom:16 }} />
          <div style={{ fontSize:22,fontWeight:600,color:'#f0ead8',letterSpacing:'-0.02em' }}>Outliers CRM</div>
          <div style={{ fontSize:13,color:'#7a6a4a',marginTop:4 }}>Sistema de Gestao</div>
        </div>
        <form onSubmit={handle} style={{ display:'flex',flexDirection:'column',gap:18 }}>
          <div>
            <label className="ll">E-mail</label>
            <input className="li" type="email" value={email} onChange={function(e){setEmail(e.target.value)}} required placeholder="seu@email.com" />
          </div>
          <div>
            <label className="ll">Senha</label>
            <input className="li" type="password" value={pw} onChange={function(e){setPw(e.target.value)}} required placeholder="......" />
          </div>
          {err && <div style={{ background:'#7f1d1d22',border:'1px solid #7f1d1d',color:'#fca5a5',padding:'10px 14px',fontSize:13,borderRadius:8 }}>{err}</div>}
          <button className="lb" type="submit" disabled={loading} style={{ marginTop:8 }}>{loading?'ENTRANDO...':'ENTRAR'}</button>
        </form>
        <div style={{ textAlign:'center',marginTop:24,fontSize:11,color:'#3d3420',fontFamily:'monospace',letterSpacing:'.1em' }}>ACESSO RESTRITO</div>
      </div>
    </div>
  )
}
